fetch('https://api.example.com/data')
  .then(response => {
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    return response.json();
  })
  .then(data => console.log(data))
  .catch(error => console.error('Fetch error:', error.message));

async function fetchData() {
  try {
    let response = await fetch('https://api.example.com/data');
    if (!response.ok) {
      throw new Error('Network response was not ok');
    }
    let data = await response.json();
    console.log(data);
  } catch (error) {
    console.error('Fetch error:', error.message);
  }
}

fetchData();

function handleError(error) {
  // Log error to a monitoring service here
  console.error('An error occurred:', error.message);
  alert('Oops! Something went wrong. Please try again later.');
}

async function loadData() {
  try {
    let response = await fetch('https://api.example.com/data');
    if (!response.ok) throw new Error('Failed to fetch');
    let data = await response.json();
    console.log(data);
  } catch (error) {
    handleError(error);
  }
}

loadData();

import { Kafka } from 'kafkajs';

const kafka = new Kafka({
  clientId: 'my-producer',
  brokers: ['localhost:9092']
});

const producer = kafka.producer();

const run = async () => {
  await producer.connect();
  console.log('Producer connected');

  // Send a message to the topic 'test-topic'
  await producer.send({
    topic: 'test-topic',
    messages: [
      { value: JSON.stringify({ event: 'user_signup', userId: 123 }) }
    ]
  });

  console.log('Message sent');
  await producer.disconnect();
};

run().catch(console.error);

import { Kafka } from 'kafkajs';

const kafka = new Kafka({
  clientId: 'my-consumer',
  brokers: ['localhost:9092']
});

const consumer = kafka.consumer({ groupId: 'test-group' });

const run = async () => {
  await consumer.connect();
  console.log('Consumer connected');

  await consumer.subscribe({ topic: 'test-topic', fromBeginning: true });

  await consumer.run({
    eachMessage: async ({ topic, partition, message }) => {
      const event = message.value ? message.value.toString() : null;
      if(event) {
        console.log(`Received event on topic ${topic}:`, JSON.parse(event));
      }
    }
  });
};

run().catch(console.error);

